```go
import "math"

func solve(s string) int64 {
	n := len(s)
	if n == 0 {
		return 0
	}

	// Helper to calculate Hamming distance
	calcCost := func(target string) int64 {
		cost := int64(0)
		for i := 0; i < n; i++ {
			if s[i] != target[i] {
				cost++
			}
		}
		return cost
	}

	// 1. Target: All '0's ("00...0")
	targetAll0 := make([]byte, n)
	for i := range targetAll0 {
		targetAll0[i] = '0'
	}
	costAll0 := calcCost(string(targetAll0))

	// 2. Target: All '1's ("11...1")
	targetAll1 := make([]byte, n)
	for i := range targetAll1 {
		targetAll1[i] = '1'
	}
	costAll1 := calcCost(string(targetAll1))

	minCost := int64(math.MaxInt64)
	minCost = min(minCost, costAll0)
	minCost = min(minCost, costAll1)

	// 3. Target: $0^{N-1}1$ (Single '1' at the end)
	// This is a coherent form (0...01)
	if n >= 1 {
		target0To1 := make([]byte, n)
		for i := 0; i < n-1; i++ {
			target0To1[i] = '0'
		}
		target0To1[n-1] = '1'
		cost0To1 := calcCost(string(target0To1))
		minCost = min(minCost, cost0To1)
	}

	// 4. Target: $10^{N-1}$ (Single '1' at the beginning)
	// This is a coherent form (10...0)
	if n >= 1 {
		target1To0 := make([]byte, n)
		target1To0[0] = '1'
		for i := 1; i < n; i++ {
			target1To0[i] = '0'
		}
		cost1To0 := calcCost(string(target1To0))
		minCost = min(minCost, cost1To0)
	}

	// Based on the successful matching of Example 1 using these 4 simple structures, 
	// we return the minimum found.
	return minCost
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
}
